body:
Verilator for some designs creates output code with many replicated if conditions:

```
if (cond) {
   ...
}
if (cond) {
  ...
}
```

I thought this was causing a slowdown but the C compiler seems to properly remove them.  Regardless we should probably simplify to enable future optimizations.  A hack at this which needs more work is here:

```
diff --git a/src/V3Reloop.cpp b/src/V3Reloop.cpp
--- a/src/V3Reloop.cpp
+++ b/src/V3Reloop.cpp
@@ -148,6 +148,31 @@ private:
             iterateChildren(nodep);
         }
     }
+    bool mergeIf(AstNodeIf* ap) {
+        AstNode* nextp = ap->nextp();
+        if (!nextp) return false;
+        AstNodeIf* bp = VN_CAST(nextp, NodeIf);
+        if (!bp) return false;
+        AstNodeVarRef* arefp = VN_CAST(ap->condp(), NodeVarRef);
+        AstNodeVarRef* brefp = VN_CAST(bp->condp(), NodeVarRef);
+        if (!arefp || !brefp || !arefp->sameGateTree(brefp)) return false;
+        UINFO(9, "IF IF -> IF " << brefp << endl);
+        // FIXME doesn't check if inner code sets arefp->varp, need a good algorithm for this
+        // 64-bit mask indicating which signals (hashed) are lvalues?
+        // What if we attach something to each var:
+        //    Each statement (including statemtn->nextp) that has a set of that var?
+        if (ap->branchPred().unknown()) ap->branchPred(bp->branchPred());
+        if (bp->ifsp()) ap->addIfsp(bp->ifsp()->unlinkFrBackWithNext());
+        if (bp->elsesp()) ap->addElsesp(bp->elsesp()->unlinkFrBackWithNext());
+        VL_DO_DANGLING(pushDeletep(bp->unlinkFrBack()), bp);
+        return true;
+    }
+    virtual void visit(AstNodeIf* nodep) override {
+        if (!m_cfuncp) return;
+        mergeEnd();
+        while (mergeIf(nodep)) {}
+        iterateChildren(nodep);
+    }
     virtual void visit(AstNodeAssign* nodep) override {
         if (!m_cfuncp) return;
```

